const fs = require("fs");
const path = require("path");

const PUBLIC_API_NAME = "public_api";

const PACKAGE_ROOT_DIR = path.resolve(__dirname, "..");
const SOURCE_DIR = path.resolve(PACKAGE_ROOT_DIR, "src");
const GENERATED_DIR = path.resolve(SOURCE_DIR, "__generated__");
const BASE_FETCHER_PATH = path.resolve(SOURCE_DIR, "base");
const BARREL_TARGET_PATH = path.resolve(GENERATED_DIR, "barrel.ts");
const PUBLIC_API_SWAGGER_PATH = path.resolve(
  GENERATED_DIR,
  "services/coordinator/public/v1/public_api.swagger.json",
);

const COMMENT_HEADER =
  "/* @generated by `@turnkey/fetchers`. DO NOT EDIT BY HAND */";

main().catch((error) => {
  console.error(error);
  process.exit(1);
});

async function main() {
  const fileInfo = await readSwaggerFile(PUBLIC_API_SWAGGER_PATH);

  await generateTypes(fileInfo);
  await generateFetcher(fileInfo);
  await generateClientFromSwagger(
    fileInfo.parsedData,
    fileInfo.absolutePath.replace(/\.swagger.json$/, ".client.ts"),
  );
}

/**
 * @typedef {{
 *   absolutePath: string;
 *   parsedData: any;
 * }} TFileInfo
 *
 * @typedef {import("swagger-schema-official").Spec} TSwaggerSpec
 * @typedef {import("swagger-schema-official").Operation} TSwaggerOperation
 * @typedef {import("swagger-schema-official").Parameter} TSwaggerParameter
 *
 * @typedef {{
 *   name: string;
 *   isBound: boolean;
 *   value: string;
 * }} TBinding
 */

/**
 * @param {string} absolutePath
 * @returns {Promise<TFileInfo>}
 */
async function readSwaggerFile(absolutePath) {
  const content = await fs.promises.readFile(absolutePath, "utf-8");

  return {
    absolutePath,
    parsedData: JSON.parse(content),
  };
}

/**
 * Run `openapi-typescript` codegen.
 *
 * @param {TFileInfo} fileInfo
 * @returns {Promise<void>}
 */
async function generateTypes(fileInfo) {
  const { default: openApiTypeScript } = await import("openapi-typescript");

  const code = await openApiTypeScript(fileInfo.parsedData, {
    exportType: true,
    formatter: /** @param {any} schemaObj */ (schemaObj) => {
      if (schemaObj["x-nullable"] === true) {
        if (schemaObj.type !== "string") {
          return undefined;
        }

        if (Array.isArray(schemaObj.enum) && schemaObj.enum.length > 0) {
          return (
            schemaObj.enum
              .map(/** @param {any} val */ (val) => JSON.stringify(val))
              .join(" | ") + "| null"
          );
        } else {
          return "string | null";
        }
      }
      return undefined;
    },
  });

  await safeWriteFileAsync(
    fileInfo.absolutePath.replace(/\.swagger.json$/, ".types.ts"),
    code,
  );
}

/**
 * Generate fetchers.
 *
 * @param {TFileInfo} fileInfo
 * @returns {Promise<void>}
 */
async function generateFetcher(fileInfo) {
  /** @type {TSwaggerSpec} */
  const spec = fileInfo.parsedData;
  const { absolutePath: sourceAbsolutePath } = fileInfo;

  const currentModuleName = path.basename(sourceAbsolutePath, ".swagger.json");
  const baseModuleImportPath = getImportRelativePath(
    sourceAbsolutePath,
    BASE_FETCHER_PATH,
  );

  // `protoc-gen-openapiv2` adds the service name as the only (?) tag.
  const namespace = spec.tags?.find((item) => item.name != null)?.name;

  if (namespace == null) {
    throw new Error(
      `Invalid namespace "${namespace}" in file "${sourceAbsolutePath}"`,
    );
  }

  /** @type {Array<string>} */
  const currentCodeBuffer = [];

  /** @type {Set<string>} */
  const importStatementSet = new Set([]);

  for (const endpointPath in spec.paths) {
    const methodMap = spec.paths[endpointPath];

    for (const method of ["get", "post"]) {
      // @ts-expect-error -- can't narrow
      if (methodMap[method] == null) {
        continue;
      }

      /** @type {TSwaggerOperation} */
      // @ts-expect-error -- can't narrow
      const operation = methodMap[method];
      const { operationId } = operation;

      if (operationId == null) {
        throw new Error(
          `Invalid operationId "${operationId}" in path "${endpointPath}"`,
        );
      }

      const operationNameWithoutNamespace = operationId.replace(
        new RegExp(`^${namespace}_`),
        "",
      );

      if (operationNameWithoutNamespace === operationId) {
        throw new Error(
          `Namespace "${namespace}" doesn't appear in operation "${operationId}" in path "${endpointPath}"`,
        );
      }

      const isEndpointDeprecated = Boolean(operation.deprecated);

      const fetcherName = `${
        operationNameWithoutNamespace.charAt(0).toLowerCase() +
        operationNameWithoutNamespace.slice(1)
      }`;
      const signedRequestGeneratorName = `sign${operationNameWithoutNamespace}`;

      /** @type {Array<TSwaggerParameter>} */
      // @ts-expect-error -- too hard to refine
      const parameterList = operation["parameters"] ?? [];
      const upperCasedMethod = method.toUpperCase();

      const endpointInfo = `\`${upperCasedMethod} ${endpointPath}\``;

      const tsDocCommentForMethod = assembleTsDocComment([
        operation.summary,
        operation.description,
        endpointInfo,
        isEndpointDeprecated ? "@deprecated" : null,
      ]);

      const tsDocCommentForSignMethod = assembleTsDocComment([
        `Request a WebAuthn assertion and return a signed \`${operationNameWithoutNamespace}\` request, ready to be POSTed to Turnkey.`,
        `See {@link ${operationNameWithoutNamespace}}`,
        isEndpointDeprecated ? "@deprecated" : null,
      ]);

      const tsDocCommentForType = assembleTsDocComment([
        endpointInfo,
        isEndpointDeprecated ? "@deprecated" : null,
      ]);

      /** @type {TBinding} */
      const responseTypeBinding = {
        name: `T${operationNameWithoutNamespace}Response`,
        isBound: true,
        value:
          operation.responses["200"] == null
            ? `void`
            : `operations["${operationId}"]["responses"]["200"]["schema"]`,
      };

      /** @type {TBinding} */
      const queryTypeBinding = {
        name: `T${operationNameWithoutNamespace}Query`,
        isBound: parameterList.find((item) => item.in === "query") != null,
        value: `operations["${operationId}"]["parameters"]["query"]`,
      };

      /** @type {TBinding} */
      const bodyTypeBinding = {
        name: `T${operationNameWithoutNamespace}Body`,
        isBound:
          method === "post" &&
          parameterList.find((item) => item.in === "body") != null,
        value: `operations["${operationId}"]["parameters"]["body"]["body"]`,
      };

      /** @type {TBinding} */
      const substitutionTypeBinding = {
        name: `T${operationNameWithoutNamespace}Substitution`,
        isBound: parameterList.find((item) => item.in === "path") != null,
        value: `operations["${operationId}"]["parameters"]["path"]`,
      };

      verifyParameterList(parameterList);

      /** @type {TBinding} */
      const inputTypeBinding = {
        name: `T${operationNameWithoutNamespace}Input`,
        isBound:
          bodyTypeBinding.isBound ||
          queryTypeBinding.isBound ||
          substitutionTypeBinding.isBound,
        value: `{ ${joinPropertyList([
          bodyTypeBinding.isBound ? `body: ${bodyTypeBinding.name}` : null,
          queryTypeBinding.isBound ? `query: ${queryTypeBinding.name}` : null,
          substitutionTypeBinding.isBound
            ? `substitution: ${substitutionTypeBinding.name}`
            : null,
        ])} }`,
      };

      currentCodeBuffer.push(
        ...[queryTypeBinding, substitutionTypeBinding]
          .filter((binding) => binding.isBound)
          .map(
            (binding) => `
              ${tsDocCommentForType}
              type ${binding.name} = ${binding.value};
            `,
          ),
      );

      currentCodeBuffer.push(
        ...[responseTypeBinding, inputTypeBinding, bodyTypeBinding]
          .filter((binding) => binding.isBound)
          .map(
            (binding) => `
              ${tsDocCommentForType}
              export type ${binding.name} = ${binding.value};
            `,
          ),
      );

      const rawFetcherInputParameter = !inputTypeBinding.isBound
        ? ""
        : `input: ${inputTypeBinding.name}`;

      const rawSignRequestInputParameters = !inputTypeBinding.isBound
        ? ""
        : `input: ${inputTypeBinding.name}, options?: TurnkeyCredentialRequestOptions`;

      const responseTypeParameter = responseTypeBinding.isBound
        ? responseTypeBinding.name
        : "void";

      switch (method) {
        case "get": {
          throw new Error(
            `Public API shouldn't have GET methods; found ${operationNameWithoutNamespace}`,
          );
        }
        case "post": {
          currentCodeBuffer.push(`
            ${tsDocCommentForMethod}
            export const ${fetcherName} = (${rawFetcherInputParameter}) =>
              request< ${joinPropertyList([
                responseTypeParameter,
                bodyTypeBinding.isBound ? bodyTypeBinding.name : "never",
                queryTypeBinding.isBound ? queryTypeBinding.name : "never",
                substitutionTypeBinding.isBound
                  ? substitutionTypeBinding.name
                  : "never",
                "never",
              ])} >({
                ${joinPropertyList([
                  `uri: "${endpointPath}"`,
                  `method: "${upperCasedMethod}"`,
                  queryTypeBinding.isBound ? "query: input.query" : null,
                  bodyTypeBinding.isBound ? "body: input.body" : null,
                  substitutionTypeBinding.isBound
                    ? "substitution: input.substitution"
                    : null,
                ])}
              });
          `);

          currentCodeBuffer.push(`
            ${tsDocCommentForSignMethod}
            export const ${signedRequestGeneratorName} = (${rawSignRequestInputParameters}) =>
              signedRequest< ${joinPropertyList([
                bodyTypeBinding.isBound ? bodyTypeBinding.name : "never",
                queryTypeBinding.isBound ? queryTypeBinding.name : "never",
                substitutionTypeBinding.isBound
                  ? substitutionTypeBinding.name
                  : "never",
              ])} >({
                ${joinPropertyList([
                  `uri: "${endpointPath}"`,
                  queryTypeBinding.isBound ? "query: input.query" : null,
                  bodyTypeBinding.isBound ? "body: input.body" : null,
                  substitutionTypeBinding.isBound
                    ? "substitution: input.substitution"
                    : null,
                  inputTypeBinding.isBound ? "options," : null,
                ])}
              });
          `);
          break;
        }
        default: {
          throw new Error(
            `Unsupported method "${method}" for "${endpointPath}"`,
          );
        }
      }
    }
  }

  if (currentCodeBuffer.length === 0) {
    throw new Error(`No fetchers generated for "${sourceAbsolutePath}"`);
  }

  const targetPath = sourceAbsolutePath.replace(
    /\.swagger.json$/,
    ".fetcher.ts",
  );

  currentCodeBuffer.unshift(`
    ${COMMENT_HEADER}

    ${[...importStatementSet].filter(Boolean).join("\n")}
    import { request, signedRequest, TurnkeyCredentialRequestOptions } from "${baseModuleImportPath}";
    import type { operations } from "./${currentModuleName}.types";
  `);

  await safeWriteFileAsync(targetPath, currentCodeBuffer.join("\n\n"));

  const barrelCode = `${COMMENT_HEADER}\n\nexport * as ${namespace} from "${getImportRelativePath(
    BARREL_TARGET_PATH,
    targetPath.replace(/\.ts$/, ""),
  )}";\n`;

  await safeWriteFileAsync(BARREL_TARGET_PATH, barrelCode);
}

/**
 * Generate HTTP client used by the SDK from the passed in swagger file.
 *
 * @param {TSwaggerSpec} spec
 * @param {string} targetPath
 * @returns {Promise<void>}
 */
async function generateClientFromSwagger(spec, targetPath) {
  // `protoc-gen-openapiv2` adds the service name as the only (?) tag.
  const namespace = spec.tags?.find((item) => item.name != null)?.name;

  if (namespace == null) {
    throw new Error(
      `Invalid namespace "${namespace}" in spec, cannot generate HTTP client`,
    );
  }

  /** @type {Set<string>} */
  const importStatementSet = new Set([
    'import { fetch, GrpcStatus, THttpConfig, TSignedRequest, TStamper, TurnkeyRequestError } from "../../../../../base";',
    'import { VERSION } from "../../../../../version";',
  ]);

  /** @type {Array<string>} */
  const codeBuffer = [];

  codeBuffer.push(`
    export class TurnkeyClient {
      config: THttpConfig;
      stamper: TStamper;
      name = "TurnkeyClient";

      constructor(config: THttpConfig, stamper: TStamper) {
        if (!config.baseUrl) {
          throw new Error(\`Missing base URL. Please verify env vars.\`);
        }

        this.config = config;
        this.stamper = stamper;
      }
      async request<TBodyType, TResponseType>(
        url: string,
        body: TBodyType
      ): Promise<TResponseType> {
        const fullUrl = this.config.baseUrl + url;
        const stringifiedBody = JSON.stringify(body);
        const stamp = await this.stamper.stamp(stringifiedBody);

        const response = await fetch(fullUrl, {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            "X-Client-Version": VERSION,
            [stamp.stampHeaderName]: stamp.stampHeaderValue,
          },
          body: stringifiedBody,
          redirect: "follow",
        });

        if (!response.ok) {
          let res: GrpcStatus;
          try {
            res = await response.json();
          } catch (_) {
            throw new Error(\`\${response.status} \${response.statusText}\`);
          }

          throw new TurnkeyRequestError(res);
        }

        const data = await response.json();
        return data as TResponseType;
      }
  `);

  for (const endpointPath in spec.paths) {
    const methodMap = spec.paths[endpointPath];
    if (methodMap.post === undefined) {
      throw new Error(`Found a non-POST endpoint in public API swagger!`);
    }

    if (methodMap.post.operationId == null) {
      throw new Error(`Invalid operationId in path "${endpointPath}"`);
    }

    const operation = methodMap.post;
    const operationId = methodMap.post.operationId;

    const operationNameWithoutNamespace = operationId.replace(
      new RegExp(`^${namespace}_`),
      "",
    );

    if (operationNameWithoutNamespace === operationId) {
      throw new Error(
        `Namespace "${namespace}" doesn't appear in operation "${operationId}" in path "${endpointPath}"`,
      );
    }

    if (operationNameWithoutNamespace === "NOOPCodegenAnchor") {
      continue;
    }

    const isEndpointDeprecated = Boolean(operation.deprecated);

    const methodName = `${
      operationNameWithoutNamespace.charAt(0).toLowerCase() +
      operationNameWithoutNamespace.slice(1)
    }`;

    const inputType = `T${operationNameWithoutNamespace}Body`;
    const responseType = `T${operationNameWithoutNamespace}Response`;

    codeBuffer.push(
      assembleTsDocComment([
        operation.description,
        `Sign the provided \`${inputType}\` with the client's \`stamp\` function, and submit the request (POST ${endpointPath}).`,
        `See also {@link stamp${operationNameWithoutNamespace}}.`,
        isEndpointDeprecated ? "@deprecated" : null,
      ]) +
        `\n${methodName} = async (input: ${inputType}): Promise<${responseType}> => {
          return this.request("${endpointPath}", input);
        }`,
    );

    codeBuffer.push(
      assembleTsDocComment([
        `Produce a \`SignedRequest\` from \`${inputType}\` by using the client's \`stamp\` function.`,
        `See also {@link ${operationNameWithoutNamespace}}.`,
        isEndpointDeprecated ? "@deprecated" : null,
      ]) +
        `\nstamp${operationNameWithoutNamespace} = async (input: ${inputType}): Promise<TSignedRequest> => {
          const fullUrl = this.config.baseUrl + "${endpointPath}";
          const body = JSON.stringify(input);
          const stamp = await this.stamper.stamp(body);
          return {
            body: body,
            stamp: stamp,
            url: fullUrl,
          };
        }`,
    );

    importStatementSet.add(
      `import type { ${inputType}, ${responseType} } from "./${PUBLIC_API_NAME}.fetcher";`,
    );
  }

  codeBuffer.push(`}`);
  const imports = [...importStatementSet].filter(Boolean).join("\n");

  await safeWriteFileAsync(
    targetPath,
    [COMMENT_HEADER].concat(imports).concat(codeBuffer).join("\n\n"),
  );
}

/**
 * See https://tsdoc.org/.
 *
 * @param {Array<string | null | undefined>} lineList
 * @returns {string}
 */
function assembleTsDocComment(lineList) {
  const result = ["/**"];
  const filtered = lineList.map((line) => line?.trim()).filter(Boolean);

  for (let i = 0; i < filtered.length; i++) {
    const line = filtered[i];

    result.push(` * ${line}`);

    if (i !== filtered.length - 1) {
      result.push(" *");
    }
  }

  result.push(" */");

  return result.join("\n");
}

/**
 * Makes sure parameters are legit.
 *
 * @param {Array<TSwaggerParameter>} parameterList
 * @returns {void}
 */
function verifyParameterList(parameterList) {
  for (const parameter of parameterList) {
    switch (parameter.in) {
      case "body":
      case "query": {
        break;
      }
      case "path": {
        if (!/^[a-zA-Z0-9_]+$/.test(parameter.name)) {
          throw new Error(
            `Invalid path substitution key: ${JSON.stringify(
              parameter.name,
            )} is not a valid variable name in JS`,
          );
        }
        break;
      }
      case "header":
      case "formData":
      default: {
        throw new Error(`Unsupported parameter type ${parameter.in}`);
      }
    }
  }
}

/**
 * @param {Array<string | null>} input
 * @returns {string}
 */
function joinPropertyList(input) {
  return input.filter(Boolean).join(",\n");
}

/**
 * Normalizes the leading "../".
 *
 * @param {string} from
 * @param {string} to
 * @returns {string}
 */
function getImportRelativePath(from, to) {
  const raw = path.relative(from, to);
  const isTrulyUpperLevel = /^\.\.\/\.\.\//.test(raw);

  return raw.replace(/^\.\.\//, isTrulyUpperLevel ? "" : "./");
}

/**
 * @param {string} targetPath
 * @param {string} content
 * @returns {Promise<void>}
 */
async function safeWriteFileAsync(targetPath, content) {
  await fs.promises.mkdir(path.dirname(targetPath), { recursive: true });
  await fs.promises.writeFile(targetPath, content, "utf-8");
}
